const ev=$('Stripe Trigger').first().json;const s=(ev.data&&ev.data.object)?ev.data.object:ev;
const li=($('Line items').first().json&&$('Line items').first().json.data)?$('Line items').first().json.data:[];
let fee=0;try{const pi=$json;const bt=pi&&pi.latest_charge&&pi.latest_charge.balance_transaction;if(bt&&typeof bt.fee==='number')fee=bt.fee/100;}catch(e){}
const COGS={pep:22.81,p4:21.68,cream:21.18,p1:20.81,p3:17.92,p2:20.81};
function slug(desc){const d=String(desc||'').toLowerCase();if(d.includes('peptide'))return'pep';if(d.includes('retinol'))return'p4';if(d.includes('moistur')||d.includes('cream'))return'cream';if(d.includes('cleanser')||d.includes('radiant')||d.includes('glow'))return'p1';if(d.includes('toner')||d.includes('purif'))return'p3';if(d.includes('shampoo')||d.includes('scalp'))return'p2';return null;}
let cogs=0,qty=0;const parts=[];for(const i of li){const q=i.quantity||1;qty+=q;const sl=slug(i.description);if(sl)cogs+=COGS[sl]*q;parts.push(q+'× '+(i.description||''));}
cogs=+cogs.toFixed(2);
const gross=((s.amount_total!=null?s.amount_total:0))/100;
const meta=s.metadata||{};const src=String(meta.channel||meta.utm_source||'').toLowerCase();
const channel=(src.includes('social')||src.includes('insta')||src.includes('face')||src.includes('pin')||src.includes('tiktok'))?'Social':'Website';
const order='EL-'+String(s.id||'').slice(-8).toUpperCase();
const date=new Date((s.created?s.created*1000:Date.now())).toISOString();
const body=JSON.stringify({parent:{database_id:'37fa4815-a826-8132-9a84-e8e0defc62be'},icon:{type:'emoji',emoji:'💶'},properties:{Name:{title:[{text:{content:channel+' · '+order+' · €'+gross.toFixed(2)}}]},Date:{date:{start:date}},Channel:{select:{name:channel}},Type:{select:{name:'Sale'}},Product:{rich_text:[{text:{content:parts.join(', ').slice(0,1900)}}]},Qty:{number:qty},Gross:{number:gross},Fees:{number:+fee.toFixed(2)},COGS:{number:cogs},'Other cost':{number:0},Profit:{number:+(gross-fee-cogs).toFixed(2)},'Order ID':{rich_text:[{text:{content:String(s.id||'')}}]}}});
return [{json:{notionBody:body,gross,fee:+fee.toFixed(2),cogs,channel,order}}];
